-- Generated by render.py — load seed CSVs into DEMO_EMPLOYEE_APP.PUBLIC
USE ROLE SYSADMIN;
USE SCHEMA DEMO_EMPLOYEE_APP.PUBLIC;
USE WAREHOUSE DEMO_WH;

COPY INTO BUSINESS_UNITS (BU_ID,NAME,HEAD_USER_ID) FROM @DEMO_SEED_STAGE/BUSINESS_UNITS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO DEPARTMENTS_DETAIL (DEPT_ID,DEPT_NAME,BU_ID,HEAD_USER_ID) FROM @DEMO_SEED_STAGE/DEPARTMENTS_DETAIL.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO EMPLOYEES (EMPLOYEE_ID,FIRST_NAME,LAST_NAME,EMAIL,DEPARTMENT,TITLE,LOCATION,STATUS,HIRE_DATE,TERMINATION_DATE,MANAGER_ID,BUSINESS_UNIT_ID,LATTICE_ID,FRESHTEAM_ID) FROM @DEMO_SEED_STAGE/EMPLOYEES.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO EMPLOYEE_FIELDS (EMPLOYEE_ID,EMPLOYMENT_TYPE,PHONE,NATIONALITY,GENDER,DATE_OF_BIRTH,NOTICE_PERIOD_DAYS) FROM @DEMO_SEED_STAGE/EMPLOYEE_FIELDS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO HEADCOUNT_PLAN (PLAN_ID,MONTH,DEPARTMENT,PLANNED_FTE,PLANNED_CONTRACTORS,PLANNED_MANAGED) FROM @DEMO_SEED_STAGE/HEADCOUNT_PLAN.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO TASKS (TASK_ID,TASK_NAME,IS_BILLABLE_DEFAULT) FROM @DEMO_SEED_STAGE/TASKS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO PROJECTS (PROJECT_ID,PROJECT_NAME,CLIENT,STATUS,START_DATE,END_DATE,HOURLY_RATE,IS_BILLABLE) FROM @DEMO_SEED_STAGE/PROJECTS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO PROJECT_ASSIGNMENTS (ASSIGNMENT_ID,EMPLOYEE_ID,PROJECT_ID,ROLE,ALLOCATION_PCT,IS_PROJECT_MANAGER) FROM @DEMO_SEED_STAGE/PROJECT_ASSIGNMENTS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO TIME_ENTRIES (ENTRY_ID,EMPLOYEE_ID,PROJECT_ID,TASK_ID,SPENT_DATE,HOURS,IS_BILLABLE,NOTES) FROM @DEMO_SEED_STAGE/TIME_ENTRIES.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO PERFORMANCE_REVIEWS (REVIEW_ID,EMPLOYEE_ID,REVIEW_DATE,REVIEW_PERIOD,RATING,SENTIMENT,SENTIMENT_SCORE,GOALS_MET,GOALS_TOTAL,MANAGER_COMMENTS) FROM @DEMO_SEED_STAGE/PERFORMANCE_REVIEWS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO LEAVE_REQUESTS (LEAVE_ID,EMPLOYEE_ID,LEAVE_TYPE,START_DATE,DAYS,STATUS,REASON) FROM @DEMO_SEED_STAGE/LEAVE_REQUESTS.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;
COPY INTO COMPANY_KNOWLEDGE_BASE (DOC_ID,TITLE,CATEGORY,AUDIENCE,CONTENT) FROM @DEMO_SEED_STAGE/COMPANY_KNOWLEDGE_BASE.csv FILE_FORMAT=(TYPE=CSV FIELD_OPTIONALLY_ENCLOSED_BY='"' SKIP_HEADER=1 NULL_IF=('','NULL','null')) FORCE=TRUE;

-- Post-load verification: every data table should be non-empty.
SELECT * FROM (
    SELECT 'BUSINESS_UNITS' AS TBL, COUNT(*) AS N FROM BUSINESS_UNITS
    UNION ALL SELECT 'DEPARTMENTS_DETAIL' AS TBL, COUNT(*) AS N FROM DEPARTMENTS_DETAIL
    UNION ALL SELECT 'EMPLOYEES' AS TBL, COUNT(*) AS N FROM EMPLOYEES
    UNION ALL SELECT 'EMPLOYEE_FIELDS' AS TBL, COUNT(*) AS N FROM EMPLOYEE_FIELDS
    UNION ALL SELECT 'HEADCOUNT_PLAN' AS TBL, COUNT(*) AS N FROM HEADCOUNT_PLAN
    UNION ALL SELECT 'TASKS' AS TBL, COUNT(*) AS N FROM TASKS
    UNION ALL SELECT 'PROJECTS' AS TBL, COUNT(*) AS N FROM PROJECTS
    UNION ALL SELECT 'PROJECT_ASSIGNMENTS' AS TBL, COUNT(*) AS N FROM PROJECT_ASSIGNMENTS
    UNION ALL SELECT 'TIME_ENTRIES' AS TBL, COUNT(*) AS N FROM TIME_ENTRIES
    UNION ALL SELECT 'PERFORMANCE_REVIEWS' AS TBL, COUNT(*) AS N FROM PERFORMANCE_REVIEWS
    UNION ALL SELECT 'LEAVE_REQUESTS' AS TBL, COUNT(*) AS N FROM LEAVE_REQUESTS
    UNION ALL SELECT 'COMPANY_KNOWLEDGE_BASE' AS TBL, COUNT(*) AS N FROM COMPANY_KNOWLEDGE_BASE
) ORDER BY N ASC, TBL;
